import React from "react";
import { SocialIcon } from 'react-social-icons';
import '../index.css';

const style = {
    position: 'relative',
    width: '100%',
    backgroundColor: '#EBA4A6',
    color: 'white',
    textAlign: 'center',
}



class Footer extends React.Component {
  render() {
    return(
      <div style={style}> 
          <SocialIcon style={{margin: "30px"}} url="https://github.com/AnnaReid22"></SocialIcon>
          <SocialIcon style={{margin: "30px"}} url="https://www.linkedin.com/in/anna-reid/"></SocialIcon>
          <SocialIcon style={{margin: "30px"}} network="email" url="mailto:reid.anna.m@gmail.com"></SocialIcon>
          <div> Copyright Anna Reid :) </div>
      </div>
  )
  }
}




export default Footer;
